package plugins.openldap.config.editor.org.apache.directory.studio.openldap.config.editor.overlays;

public class ModuleWrapper { private String moduleListName ; private int moduleListIndex ; private String moduleName ; private String path ; private int order ; public ModuleWrapper ( ) { } public ModuleWrapper ( String moduleListName , int moduleListIndex , String module , String path , int order ) { this . moduleListName = moduleListName ; this . moduleName = module ; this . path = path ; this . moduleListIndex = moduleListIndex ; this . order = order ; } public String getModuleListName ( ) { return moduleListName ; } public int getModuleListIndex ( ) { return moduleListIndex ; } public String getModuleName ( ) { return moduleName ; } public String getPath ( ) { return path ; } public int getOrder ( ) { return order ; } public void setModuleName ( String moduleName ) { this . moduleName = moduleName ; } public void setModuleIndex ( int moduleListIndex ) { this . moduleListIndex = moduleListIndex ; } public void setPath ( String path ) { this . path = path ; } public void setModuleListName ( String moduleListName ) { this . moduleListName = moduleListName ; } public void setOrder ( int order ) { this . order = order ; } public String getModulePathName ( ) { StringBuilder sb = new StringBuilder ( ) ; if ( path != null ) { sb . append ( path ) . append ( "/" ) ; } sb . append ( "{" ) . append ( order ) . append ( '}' ) . append ( moduleName ) ; return sb . toString ( ) ; } public String toString ( ) { StringBuilder sb = new StringBuilder ( ) ; sb . append ( moduleListName ) . append ( '{' ) . append ( moduleListIndex ) . append ( '}' ) ; sb . append ( ':' ) ; if ( path != null ) { sb . append ( path ) . append ( "/" ) ; } sb . append ( "{" ) . append ( order ) . append ( '}' ) . append ( moduleName ) ; return sb . toString ( ) ; } }